import{mostrarResultado}from"../../renderResult.js";export function render(n){const{accion:o,articulos:t,articulo:a,mensaje:i}=n.respuesta;if("listar"!==o&&o)mostrarResultado("editar"===o?`\n            <h3>✏️ Editar artículo</h3>\n            <p><b>Título:</b> ${a.titulo}</p>\n            <p><b>Contenido:</b> ${a.contenido}</p>\n            <button onclick="sendPrompt('accion=modificar&id=${a.id}&titulo=NuevoTitulo&contenido=NuevoContenido')">\n                💾 Guardar cambios\n            </button>\n            <button onclick="sendPrompt('accion=listar')">❌ Cancelar</button>\n        `:`\n            <p>${i}</p>\n            <button onclick="sendPrompt('accion=listar')">← Volver al blog</button>\n        `);else{const n=t.map(n=>`\n            <article style="border-bottom:1px solid #ddd; padding:16px 0; margin-bottom:8px;">\n                <h2 style="margin:0 0 4px 0;">${n.titulo}</h2>\n                <small style="color:#888;">📅 ${n.fecha}</small>\n                <p style="margin:8px 0;">${n.contenido}</p>\n                <button onclick="sendPrompt('accion=editar&id=${n.id}')">✏️ Editar</button>\n                <button onclick="sendPrompt('accion=baja&id=${n.id}')">🗑 Eliminar</button>\n            </article>\n        `).join("");mostrarResultado(`\n            <header style="background:#333; color:#fff; padding:16px; border-radius:8px 8px 0 0;">\n                <h1 style="margin:0;">📝 Mi Blog</h1>\n            </header>\n            <main style="padding:12px;">\n                <button onclick="sendPrompt('accion=alta')">+ Nuevo artículo</button>\n                <hr>\n                ${n||"<p>No hay artículos todavía.</p>"}\n            </main>\n            <footer style="background:#eee; padding:10px; border-radius:0 0 8px 8px; text-align:center;">\n                <small>Blog creado con PHP y BD</small>\n            </footer>\n        `)}}//# sourceMappingURL=ejercicio2.js.map
